+func TestSanitizePaneID(t *testing.T) {
+	t.Parallel()
+	cases := []struct {
+		in, want string
+	}{
+		{"%0", "0"},
+		{"%123", "123"},
+		{"42", "42"},
+		{"%foo/bar", "foo_bar"},
+		{"", "unknown"},
+		{"%", "unknown"},
+		{"main:0:2", "main-0-2"},
+		{"my_session:1:0", "my_session-1-0"},
+	}
+	for _, c := range cases {
+		if got := sanitizePaneID(c.in); got != c.want {
+			t.Errorf("sanitizePaneID(%q) = %q; want %q", c.in, got, c.want)
+		}
+	}
+}
