+func TestMigrateLegacyIdentityIfNeeded(t *testing.T) {
+	tmp := t.TempDir()
+	t.Setenv("XDG_CONFIG_HOME", tmp)
+	t.Setenv("HOME", tmp)
+	t.Setenv("XDG_STATE_HOME", filepath.Join(tmp, "state"))
